import { puzzleGrid, currentGrid, invalidCells as invalidCellStore, gameStore } from './domainGame'

export const invalidCells = invalidCellStore

export const grid = {
	subscribe: puzzleGrid.subscribe,

	generate(difficulty) {
		gameStore.startGenerated(difficulty)
	},

	decodeSencode(sencode) {
		gameStore.startFromSencode(sencode)
	},

	get(gridStore, x, y) {
		return gridStore[y][x]
	},

	getSencode(gridStore = null) {
		return gridStore ? gridStore && gridStore.length ? gameStore.encodeCurrentPuzzle() : '' : gameStore.encodeCurrentPuzzle()
	},
}

export const userGrid = {
	subscribe: currentGrid.subscribe,

	set(pos, value) {
		gameStore.guess(pos, value)
	},

	applyHint(pos) {
		gameStore.applyHint(pos)
	},

	getCandidateHint(pos) {
		return gameStore.getCandidateHint(pos)
	},

	getNextHint() {
		return gameStore.getNextHint()
	},
}
